/**
 * thesmos ai:fingerprint
 *
 * Detects evidence that files were AI-generated using static heuristics:
 *   - Git log Co-Authored-By markers (Claude, GitHub Copilot, Cursor, Codex)
 *   - Comment patterns characteristic of AI tools (boilerplate docstrings,
 *     "This file is auto-generated by..." headers, excessive inline comments)
 *   - Structural patterns: duplicate error handlers, identical try/catch
 *     scaffolding across unrelated files
 *
 * Output:
 *   { aiGeneratedEstimate: '72%', topTool: 'claude-code', byFile: [...] }
 *
 * Usage:
 *   thesmos ai:fingerprint [--format json|text] [--output FILE] [--min-confidence N]
 */

import { join } from 'node:path';
import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { execSync } from 'node:child_process';

// ── Types ─────────────────────────────────────────────────────────────────────

interface FileSignal {
  path: string;
  confidence: number; // 0–100
  signals: string[];
  tool: string | null;
}

interface FingerprintResult {
  aiGeneratedEstimate: string;
  topTool: string | null;
  filesAnalyzed: number;
  filesWithSignals: number;
  byFile: FileSignal[];
  summary: ToolSummary[];
}

interface ToolSummary {
  tool: string;
  fileCount: number;
  percentage: string;
}

interface GitCommit {
  hash: string;
  coAuthors: string[];
  message: string;
  files: string[];
}

// ── Constants ─────────────────────────────────────────────────────────────────

const AI_COAUTHOR_PATTERNS: Array<{ pattern: RegExp; tool: string }> = [
  { pattern: /claude(?:\s+(?:code|sonnet|opus|haiku|ai))?/i, tool: 'claude-code' },
  { pattern: /github[-\s]copilot/i, tool: 'copilot' },
  { pattern: /cursor[-\s]ai/i, tool: 'cursor' },
  { pattern: /codex/i, tool: 'codex' },
  { pattern: /openai/i, tool: 'openai' },
  { pattern: /gemini(?:[-\s]code)?/i, tool: 'gemini' },
  { pattern: /codewhisperer/i, tool: 'codewhisperer' },
  { pattern: /tabnine/i, tool: 'tabnine' },
  { pattern: /noreply@anthropic\.com/i, tool: 'claude-code' },
];

const AI_COMMENT_PATTERNS: Array<{ pattern: RegExp; signal: string; weight: number }> = [
  // Boilerplate headers
  { pattern: /\/\*\*?\s*\n\s*\*\s*@generated\b/, signal: '@generated annotation', weight: 40 },
  { pattern: /\/\/\s*This file (?:was |is )?(?:auto-)?generated/i, signal: 'auto-generated header', weight: 35 },
  { pattern: /\/\/\s*Generated by (?:Claude|Copilot|Cursor|AI|ChatGPT)/i, signal: 'generated-by comment', weight: 60 },
  { pattern: /Co-Authored-By:.*(?:claude|copilot|cursor|codex|gemini)/i, signal: 'Co-Authored-By marker in source', weight: 80 },

  // Over-commented code (AI explains everything)
  { pattern: /\/\/ (?:Initialize|Create|Get|Set|Return|Check|Loop|Iterate|Map|Filter|Reduce) the /i, signal: 'over-explained variable comment', weight: 15 },
  { pattern: /\/\/ Step \d+:/i, signal: 'step-numbered comment', weight: 20 },
  { pattern: /\/\/ (?:First|Next|Then|Finally|Note|Important|TODO:|FIXME:|HACK:)\b/i, signal: 'AI narration comment', weight: 10 },

  // Structural patterns
  { pattern: /\/\/ eslint-disable-next-line.*\n.*(?:eslint-disable-next-line)/m, signal: 'repeated eslint-disable block', weight: 15 },
  {
    pattern: /try\s*\{[^}]{1,200}\}\s*catch\s*\((?:error|err|e)\)\s*\{\s*console\.(error|log)\s*\([^)]*(?:error|err|e)\)/s,
    signal: 'AI boilerplate try/catch with console.error',
    weight: 20,
  },

  // Type annotation overkill
  { pattern: /:\s*(?:string|number|boolean)\s*\|\s*(?:string|number|boolean)\s*\|\s*(?:string|number|boolean)/g, signal: 'verbose union type annotation', weight: 10 },

  // Excessive JSDoc
  { pattern: /\/\*\*[\s\S]{0,50}@param\s+\{\w+\}\s+\w+\s+The \w+/m, signal: 'AI docstring "The <param>" pattern', weight: 15 },
  { pattern: /\/\*\*[\s\S]{0,50}@returns\s+\{\w+\}\s+The \w+/m, signal: 'AI docstring "The return value" pattern', weight: 15 },
];

// ── Helpers ───────────────────────────────────────────────────────────────────

function parseArgs(argv: string[]): {
  format: 'json' | 'text';
  output: string | null;
  minConfidence: number;
} {
  let format: 'json' | 'text' = 'text';
  let output: string | null = null;
  let minConfidence = 0;

  for (let i = 0; i < argv.length; i++) {
    if (argv[i] === '--format' && argv[i + 1]) {
      const fmt = argv[++i]!;
      if (fmt === 'json' || fmt === 'text') format = fmt;
    } else if (argv[i]?.startsWith('--format=')) {
      const fmt = argv[i]!.slice('--format='.length);
      if (fmt === 'json' || fmt === 'text') format = fmt;
    } else if (argv[i] === '--output' && argv[i + 1]) {
      output = argv[++i]!;
    } else if (argv[i]?.startsWith('--output=')) {
      output = argv[i]!.slice('--output='.length);
    } else if (argv[i] === '--min-confidence' && argv[i + 1]) {
      minConfidence = parseInt(argv[++i]!, 10) || 0;
    } else if (argv[i]?.startsWith('--min-confidence=')) {
      minConfidence = parseInt(argv[i]!.slice('--min-confidence='.length), 10) || 0;
    }
  }

  return { format, output, minConfidence };
}

function readGitLog(root: string): GitCommit[] {
  try {
    // Format: hash|subject|body (NUL separated)
    const raw = execSync(
      'git log --format="%H|%s|%b|%N" --name-only -n 200',
      { cwd: root, encoding: 'utf8', stdio: ['pipe', 'pipe', 'pipe'] },
    );

    const commits: GitCommit[] = [];
    const blocks = raw.split(/\n(?=[0-9a-f]{40}\|)/);

    for (const block of blocks) {
      const lines = block.split('\n');
      const header = lines[0];
      if (!header) continue;

      const pipeIdx = header.indexOf('|');
      if (pipeIdx < 0) continue;
      const hash = header.slice(0, pipeIdx);
      const rest = header.slice(pipeIdx + 1);

      const coAuthors: string[] = [];
      const coAuthorRe = /Co-Authored-By:\s*([^\n]+)/gi;
      let m: RegExpExecArray | null;
      while ((m = coAuthorRe.exec(rest + '\n' + lines.slice(1).join('\n'))) !== null) {
        coAuthors.push(m[1]!.trim());
      }

      const files = lines.slice(1).filter((l) => l.trim() && !l.startsWith(' '));

      commits.push({ hash, coAuthors, message: rest, files });
    }

    return commits;
  } catch {
    return [];
  }
}

function getToolFromCoAuthors(coAuthors: string[]): string | null {
  for (const author of coAuthors) {
    for (const { pattern, tool } of AI_COAUTHOR_PATTERNS) {
      if (pattern.test(author)) return tool;
    }
  }
  return null;
}

function analyzeFile(filePath: string, root: string): { signals: string[]; confidence: number; tool: string | null } {
  const absPath = join(root, filePath);
  if (!existsSync(absPath)) return { signals: [], confidence: 0, tool: null };

  let content: string;
  try {
    content = readFileSync(absPath, 'utf8');
  } catch {
    return { signals: [], confidence: 0, tool: null };
  }

  const signals: string[] = [];
  let totalWeight = 0;
  let tool: string | null = null;

  for (const { pattern, signal, weight } of AI_COMMENT_PATTERNS) {
    if (pattern.test(content)) {
      signals.push(signal);
      totalWeight += weight;
      if (weight >= 60 && !tool) {
        // High-confidence signal — try to extract specific tool
        if (/claude/i.test(content)) tool = 'claude-code';
        else if (/copilot/i.test(content)) tool = 'copilot';
        else if (/cursor/i.test(content)) tool = 'cursor';
        else if (/codex/i.test(content)) tool = 'codex';
      }
    }
  }

  // Cap at 95 — static analysis can't be certain
  const confidence = Math.min(95, totalWeight);
  return { signals, confidence, tool };
}

function collectSourceFiles(root: string, maxFiles = 500): string[] {
  const result: string[] = [];
  const skipDirs = new Set(['node_modules', '.git', '.next', 'dist', 'build', 'coverage', '.turbo']);

  function walk(dir: string): void {
    if (result.length >= maxFiles) return;
    let entries;
    try {
      entries = readdirSync(dir, { withFileTypes: true });
    } catch {
      return;
    }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        if (!skipDirs.has(entry.name) && !entry.name.startsWith('.')) {
          walk(join(dir, entry.name));
        }
      } else if (/\.(ts|tsx|js|jsx|mjs|cjs|py|go|rb|java|rs)$/.test(entry.name)) {
        const rel = join(dir, entry.name).slice(root.length + 1);
        result.push(rel);
      }
    }
  }

  walk(root);
  return result;
}

// ── Core analysis ─────────────────────────────────────────────────────────────

function fingerprint(root: string): FingerprintResult {
  // Phase 1: git log — build a map of file → ai tool from commit metadata
  const commits = readGitLog(root);
  const fileToolMap = new Map<string, string>(); // file → tool from git
  const fileGitSignals = new Map<string, string[]>(); // file → git signals

  for (const commit of commits) {
    const tool = getToolFromCoAuthors(commit.coAuthors);
    if (tool) {
      for (const f of commit.files) {
        if (!fileToolMap.has(f)) {
          fileToolMap.set(f, tool);
          fileGitSignals.set(f, [`Co-Authored-By commit (${tool})`]);
        }
      }
    }
  }

  // Phase 2: static file content analysis
  const sourceFiles = collectSourceFiles(root);
  const byFile: FileSignal[] = [];

  for (const filePath of sourceFiles) {
    const gitTool = fileToolMap.get(filePath) ?? null;
    const gitSignals = fileGitSignals.get(filePath) ?? [];
    const { signals: contentSignals, confidence: contentConfidence, tool: contentTool } = analyzeFile(filePath, root);

    const allSignals = [...gitSignals, ...contentSignals];
    if (allSignals.length === 0) continue;

    // Git co-author in commit = 70 confidence baseline
    const gitConfidence = gitTool ? 70 : 0;
    const confidence = Math.min(99, Math.max(gitConfidence, contentConfidence) + Math.min(20, allSignals.length * 5));
    const tool = gitTool ?? contentTool;

    byFile.push({ path: filePath, confidence, signals: allSignals, tool });
  }

  byFile.sort((a, b) => b.confidence - a.confidence);

  // Phase 3: aggregate stats
  const filesWithSignals = byFile.length;
  const filesAnalyzed = sourceFiles.length;

  // Weight by confidence to estimate overall AI %
  const totalConfidence = byFile.reduce((sum, f) => sum + f.confidence, 0);
  const maxPossible = filesAnalyzed * 99;
  const aiPct = maxPossible > 0 ? Math.round((totalConfidence / maxPossible) * 100) : 0;
  const aiGeneratedEstimate = `${aiPct}%`;

  // Top tool by file count
  const toolCounts = new Map<string, number>();
  for (const f of byFile) {
    if (f.tool) toolCounts.set(f.tool, (toolCounts.get(f.tool) ?? 0) + 1);
  }

  let topTool: string | null = null;
  let topCount = 0;
  for (const [tool, count] of toolCounts) {
    if (count > topCount) { topCount = count; topTool = tool; }
  }

  const summary: ToolSummary[] = [...toolCounts.entries()]
    .sort((a, b) => b[1] - a[1])
    .map(([tool, count]) => ({
      tool,
      fileCount: count,
      percentage: `${Math.round((count / Math.max(1, filesWithSignals)) * 100)}%`,
    }));

  return { aiGeneratedEstimate, topTool, filesAnalyzed, filesWithSignals, byFile, summary };
}

// ── Formatters ────────────────────────────────────────────────────────────────

function formatText(result: FingerprintResult, minConfidence: number): string {
  const lines: string[] = [
    `Thesmos AI Code Fingerprint`,
    `═══════════════════════════════`,
    ``,
    `  Files analyzed:       ${result.filesAnalyzed}`,
    `  Files with AI signals: ${result.filesWithSignals}`,
    `  AI-generated estimate: ${result.aiGeneratedEstimate}`,
    `  Top tool:             ${result.topTool ?? '—'}`,
    ``,
  ];

  if (result.summary.length > 0) {
    lines.push(`Tool breakdown:`);
    for (const s of result.summary) {
      lines.push(`  ${s.tool.padEnd(20)} ${s.fileCount} file(s)  ${s.percentage}`);
    }
    lines.push('');
  }

  const visible = result.byFile.filter((f) => f.confidence >= minConfidence);
  if (visible.length === 0) {
    lines.push(`No files above ${minConfidence}% confidence threshold.`);
  } else {
    lines.push(`Top AI-generated files (confidence ≥ ${minConfidence}%):`);
    lines.push('');
    for (const f of visible.slice(0, 30)) {
      lines.push(`  ${f.confidence.toString().padStart(3)}%  ${f.path}`);
      if (f.tool) lines.push(`       tool: ${f.tool}`);
      for (const s of f.signals) {
        lines.push(`       · ${s}`);
      }
      lines.push('');
    }
    if (visible.length > 30) {
      lines.push(`  ... and ${visible.length - 30} more files.`);
    }
  }

  return lines.join('\n') + '\n';
}

// ── Entry point ───────────────────────────────────────────────────────────────

export async function cmdAiFingerprint(argv: string[]): Promise<void> {
  const { format, output, minConfidence } = parseArgs(argv);
  const root = process.cwd();

  const result = fingerprint(root);
  const filtered = {
    ...result,
    byFile: result.byFile.filter((f) => f.confidence >= minConfidence),
  };

  let out: string;
  if (format === 'json') {
    out = JSON.stringify(filtered, null, 2) + '\n';
  } else {
    out = formatText(result, minConfidence);
  }

  if (output) {
    const { writeFileSync } = await import('node:fs');
    writeFileSync(output, out, 'utf8');
    process.stdout.write(`AI fingerprint report written to ${output}\n`);
  } else {
    process.stdout.write(out);
  }
}
